14	namespace deep_ep::symmetric {
15	
16	static constexpr int64_t kNumAlignmentBytes = 2097152;
17	
18	// CPU communicator types: (pid, fd) handle and list of handles from all ranks
19	using cpu_handle_t = std::pair<int, int>;
20	using cpu_comm_t = std::vector<cpu_handle_t>;
21	
22	struct DeviceContext {
23	    int device_idx;
24	    CUdevice device;
25	    int numa_idx;
26	
27	    DeviceContext() {
28	        CUDA_RUNTIME_CHECK(cudaGetDevice(&device_idx));
29	        CUDA_DRIVER_CHECK(lazy_cuDeviceGet(&device, device_idx));
30	        CUDA_DRIVER_CHECK(lazy_cuDeviceGetAttribute(&numa_idx, CU_DEVICE_ATTRIBUTE_HOST_NUMA_ID, device));
31	    }
32	
33	    CUmemAllocationProp gpu_alloc_prop() const { return build_alloc_prop(CU_MEM_LOCATION_TYPE_DEVICE, device_idx); }
34	    CUmemAllocationProp cpu_alloc_prop() const { return build_alloc_prop(CU_MEM_LOCATION_TYPE_HOST_NUMA, numa_idx); }
35	
36	private:
37	    CUmemAllocationProp build_alloc_prop(const CUmemLocationType& location_type, const int& location_idx) const {
38	        CUmemAllocationProp prop = {};
39	        prop.type = CU_MEM_ALLOCATION_TYPE_PINNED;
40	        prop.location.type = location_type;
41	        prop.location.id = location_idx;
42	
43	        int requested_handle_types = CU_MEM_HANDLE_TYPE_POSIX_FILE_DESCRIPTOR;
44	        int flag = 0;
45	#if CUDART_VERSION >= 13000
46	        CUDA_DRIVER_CHECK(lazy_cuDeviceGetAttribute(&flag, CU_DEVICE_ATTRIBUTE_HANDLE_TYPE_FABRIC_SUPPORTED, device));
47	        if (flag)
48	            requested_handle_types |= CU_MEM_HANDLE_TYPE_FABRIC;
49	#endif
50	        prop.requestedHandleTypes = static_cast<CUmemAllocationHandleType>(requested_handle_types);
51	
52	        if (location_type == CU_MEM_LOCATION_TYPE_DEVICE) {
53	            flag = 0;
54	#if CUDART_VERSION >= 13000
55	            CUDA_DRIVER_CHECK(lazy_cuDeviceGetAttribute(&flag, CU_DEVICE_ATTRIBUTE_GPU_DIRECT_RDMA_WITH_CUDA_VMM_SUPPORTED, device));
56	#else
57	            CUDA_DRIVER_CHECK(lazy_cuDeviceGetAttribute(&flag, CU_DEVICE_ATTRIBUTE_GPU_DIRECT_RDMA_SUPPORTED, device));
58	#endif
59	            EP_HOST_ASSERT(flag and "GPUDirect RDMA with CUDA VMM is not supported on this device");
60	            prop.allocFlags.gpuDirectRDMACapable = 1;
61	        }
62	
63	        // Check granularity
64	        size_t num_granularity_bytes = 0;
65	        CUDA_DRIVER_CHECK(lazy_cuMemGetAllocationGranularity(&num_granularity_bytes, &prop, CU_MEM_ALLOC_GRANULARITY_RECOMMENDED));
66	        EP_HOST_ASSERT((num_granularity_bytes == 0 or kNumAlignmentBytes % num_granularity_bytes == 0) and
67	                       "Alignment must be a multiple of CUDA allocation granularity");
68	        return prop;
69	    }
70	};
