72	// Try cuMemCreate with FABRIC fallback (mirrors ncclMemAlloc logic)
73	static void cumem_create_with_fallback(CUmemGenericAllocationHandle* handle,
74	                                       const int64_t& num_bytes, CUmemAllocationProp* prop) {
75	    if (prop->requestedHandleTypes & CU_MEM_HANDLE_TYPE_FABRIC) {
76	        CUresult err = lazy_cuMemCreate(handle, num_bytes, prop, 0);
77	        if (err == CUDA_ERROR_NOT_PERMITTED or err == CUDA_ERROR_NOT_SUPPORTED) {
78	            prop->requestedHandleTypes = static_cast<CUmemAllocationHandleType>(
79	                prop->requestedHandleTypes & ~CU_MEM_HANDLE_TYPE_FABRIC);
80	            CUDA_DRIVER_CHECK(lazy_cuMemCreate(handle, num_bytes, prop, 0));
81	        } else {
82	            CUDA_DRIVER_CHECK(err);
83	        }
84	    } else {
85	        CUDA_DRIVER_CHECK(lazy_cuMemCreate(handle, num_bytes, prop, 0));
86	    }
87	}
