89	// Set read/write access for all peer GPUs, and optionally a NUMA node
90	static void set_access(const CUdeviceptr& addr, const int64_t& num_bytes,
91	                       const int& device_idx, const int& numa_idx = -1) {
92	    const bool with_cpu = (numa_idx >= 0);
93	    CUmemAccessDesc desc[2];
94	    desc[0].location.type = CU_MEM_LOCATION_TYPE_DEVICE;
95	    desc[0].flags = CU_MEM_ACCESS_FLAGS_PROT_READWRITE;
96	    if (with_cpu) {
97	        desc[1].location.type = CU_MEM_LOCATION_TYPE_HOST_NUMA;
98	        desc[1].location.id = numa_idx;
99	        desc[1].flags = CU_MEM_ACCESS_FLAGS_PROT_READWRITE;
100	    }
101	
102	    int num_devices;
103	    CUDA_RUNTIME_CHECK(cudaGetDeviceCount(&num_devices));
104	    for (int i = 0; i < num_devices; ++ i) {
105	        int can_access_peer = 0;
106	        if (i == device_idx or (cudaDeviceCanAccessPeer(&can_access_peer, i, device_idx) == cudaSuccess and can_access_peer)) {
107	            desc[0].location.id = i;
108	            CUDA_DRIVER_CHECK(lazy_cuMemSetAccess(addr, num_bytes, desc, with_cpu ? 2 : 1));
109	        }
110	    }
111	}
112	
113	class SymmetricMemory {
114	public:
115	    void* ptr = nullptr;
116	    int64_t num_bytes = 0;
117	    int64_t num_gpu_bytes = 0;
118	    int64_t num_cpu_bytes = 0;
119	
120	    virtual ~SymmetricMemory() noexcept(0) = default;
121	};
122	
123	// Wraps ncclMemAlloc/ncclMemFree (pure GPU, current default)
124	class GPUSymmetricMemory final : public SymmetricMemory {
125	public:
126	    explicit GPUSymmetricMemory(const int64_t& num_bytes) {
127	        EP_HOST_ASSERT(num_bytes > 0 and num_bytes % kNumAlignmentBytes == 0);
128	        NCCL_CHECK(ncclMemAlloc(&ptr, num_bytes));
129	        EP_HOST_ASSERT(reinterpret_cast<uint64_t>(ptr) % kNumAlignmentBytes == 0);
130	        this->num_bytes = num_bytes;
131	        this->num_gpu_bytes = num_bytes;
132	    }
133	
134	    ~GPUSymmetricMemory() override {
135	        if (ptr != nullptr) {
136	            NCCL_CHECK(ncclMemFree(ptr));
137	            ptr = nullptr;
138	        }
139	    }
140	};
141	
142	// GPU + CPU mixed allocation via CUDA Driver API
143	// Memory layout: [GPU VRAM (front)] [CPU RAM / NUMA-local (back)]
144	// The entire contiguous VA range is compatible with `ncclCommWindowRegister`.
145	class ElasticSymmetricMemory : public SymmetricMemory {
146	    CUmemGenericAllocationHandle gpu_handle = {};
147	    CUmemGenericAllocationHandle cpu_handle = {};
148	
149	public:
150	    ElasticSymmetricMemory(const int64_t& num_gpu_bytes, const int64_t& num_cpu_bytes) {
151	        EP_HOST_ASSERT(num_gpu_bytes > 0 and num_gpu_bytes % kNumAlignmentBytes == 0);
152	        EP_HOST_ASSERT(num_cpu_bytes > 0 and num_cpu_bytes % kNumAlignmentBytes == 0);
153	
154	        DeviceContext ctx;
155	        auto gpu_prop = ctx.gpu_alloc_prop();
156	        auto cpu_prop = ctx.cpu_alloc_prop();
157	
158	        this->num_gpu_bytes = num_gpu_bytes;
159	        this->num_cpu_bytes = num_cpu_bytes;
160	        this->num_bytes = num_gpu_bytes + num_cpu_bytes;
161	
162	        // Reserve VA and map segments
163	        CUdeviceptr addr;
164	        CUDA_DRIVER_CHECK(lazy_cuMemAddressReserve(&addr, this->num_bytes, kNumAlignmentBytes, 0, 0));
165	        this->ptr = reinterpret_cast<void*>(static_cast<uintptr_t>(addr));
166	
167	        cumem_create_with_fallback(&gpu_handle, num_gpu_bytes, &gpu_prop);
168	        CUDA_DRIVER_CHECK(lazy_cuMemMap(addr, num_gpu_bytes, 0, gpu_handle, 0));
169	        set_access(addr, num_gpu_bytes, ctx.device_idx);
170	
171	        cumem_create_with_fallback(&cpu_handle, num_cpu_bytes, &cpu_prop);
172	        CUDA_DRIVER_CHECK(lazy_cuMemMap(addr + num_gpu_bytes, num_cpu_bytes, 0, cpu_handle, 0));
173	        set_access(addr + num_gpu_bytes, num_cpu_bytes, ctx.device_idx, ctx.numa_idx);
174	
175	        EP_HOST_ASSERT(reinterpret_cast<uint64_t>(ptr) % kNumAlignmentBytes == 0);
176	    }
177	
178	    ~ElasticSymmetricMemory() override {
179	        auto addr = static_cast<CUdeviceptr>(reinterpret_cast<uintptr_t>(ptr));
180	        CUDA_DRIVER_CHECK(lazy_cuMemUnmap(addr, num_gpu_bytes));
181	        CUDA_DRIVER_CHECK(lazy_cuMemRelease(gpu_handle));
182	        CUDA_DRIVER_CHECK(lazy_cuMemUnmap(addr + num_gpu_bytes, num_cpu_bytes));
183	        CUDA_DRIVER_CHECK(lazy_cuMemRelease(cpu_handle));
184	        CUDA_DRIVER_CHECK(lazy_cuMemAddressFree(addr, num_bytes));
185	    }
186	};
187	
188	// Each rank creates its own NUMA-local CPU segment;
189	// CPU segments are imported and mapped contiguously into every rank's VA space.
190	// Layout: [GPU VRAM (front)] [CPU rank0 | CPU rank1 | ... | CPU rank(N-1) (back)]
191	class HybridElasticSymmetricMemory final : public SymmetricMemory {
192	    int num_scaleup_ranks;
193	    CUmemGenericAllocationHandle gpu_handle = {};
194	    std::vector<CUmemGenericAllocationHandle> cpu_handles;
195	    int local_export_fd = -1;
196	
197	public:
198	    HybridElasticSymmetricMemory(const cpu_comm_t& cpu_comm,
199	                                 const int64_t& num_gpu_bytes, const int64_t& num_cpu_bytes,
200	                                 const int& num_scaleup_ranks, const int& scaleout_rank_idx):
201	        num_scaleup_ranks(num_scaleup_ranks),
202	        cpu_handles(num_scaleup_ranks) {
203	        EP_HOST_ASSERT(num_gpu_bytes > 0 and num_gpu_bytes % kNumAlignmentBytes == 0);
204	        EP_HOST_ASSERT(num_cpu_bytes > 0 and num_cpu_bytes % kNumAlignmentBytes == 0);
205	
206	        DeviceContext ctx;
207	        auto gpu_prop = ctx.gpu_alloc_prop();
208	
209	        this->num_gpu_bytes = num_gpu_bytes;
210	        this->num_cpu_bytes = num_cpu_bytes;
211	        this->num_bytes = num_gpu_bytes + num_cpu_bytes * num_scaleup_ranks;
212	
213	        // Reserve VA
214	        CUdeviceptr addr;
215	        CUDA_DRIVER_CHECK(lazy_cuMemAddressReserve(&addr, this->num_bytes, kNumAlignmentBytes, 0, 0));
216	        this->ptr = reinterpret_cast<void*>(static_cast<uintptr_t>(addr));
217	
218	        // Map GPU segment
219	        cumem_create_with_fallback(&gpu_handle, num_gpu_bytes, &gpu_prop);
220	        CUDA_DRIVER_CHECK(lazy_cuMemMap(addr, num_gpu_bytes, 0, gpu_handle, 0));
221	        set_access(addr, num_gpu_bytes, ctx.device_idx);
222	
223	        // Import and map all intra-node CPU segments
224	        const auto local_pid = getpid();
225	        for (int i = 0; i < num_scaleup_ranks; ++ i) {
226	            auto [pid, fd] = cpu_comm[num_scaleup_ranks * scaleout_rank_idx + i];
227	            int local_fd = fd;
228	            if (pid != local_pid) {
229	                int pidfd = syscall(SYS_pidfd_open, pid, 0);
230	                EP_HOST_ASSERT(pidfd >= 0 and "`pidfd_open` failed");
231	                local_fd = syscall(SYS_pidfd_getfd, pidfd, fd, 0);
232	                EP_HOST_ASSERT(local_fd >= 0 and "`pidfd_getfd` failed");
233	                close(pidfd);
234	            }
235	
236	            const auto offset = num_gpu_bytes + i * num_cpu_bytes;
237	            CUDA_DRIVER_CHECK(lazy_cuMemImportFromShareableHandle(
238	                &cpu_handles[i],
239	                reinterpret_cast<void*>(static_cast<uintptr_t>(local_fd)),
240	                CU_MEM_HANDLE_TYPE_POSIX_FILE_DESCRIPTOR));
241	            CUDA_DRIVER_CHECK(lazy_cuMemMap(addr + offset, num_cpu_bytes, 0, cpu_handles[i], 0));
242	            set_access(addr + offset, num_cpu_bytes, ctx.device_idx, ctx.numa_idx);
243	
244	            if (pid != local_pid) {
245	                close(local_fd);
246	            } else {
247	                local_export_fd = local_fd;
248	            }
249	        }
250	
251	        EP_HOST_ASSERT(reinterpret_cast<uint64_t>(ptr) % kNumAlignmentBytes == 0);
252	    }
253	
254	    ~HybridElasticSymmetricMemory() override {
255	        auto addr = static_cast<CUdeviceptr>(reinterpret_cast<uintptr_t>(ptr));
256	
257	        CUDA_DRIVER_CHECK(lazy_cuMemUnmap(addr, num_gpu_bytes));
258	        CUDA_DRIVER_CHECK(lazy_cuMemRelease(gpu_handle));
259	
260	        if (local_export_fd >= 0)
261	            close(local_export_fd);
262	        CUDA_DRIVER_CHECK(lazy_cuMemUnmap(addr + num_gpu_bytes, num_cpu_bytes * num_scaleup_ranks));
263	        for (int i = 0; i < num_scaleup_ranks; ++ i)
264	            CUDA_DRIVER_CHECK(lazy_cuMemRelease(cpu_handles[i]));
265	
266	        CUDA_DRIVER_CHECK(lazy_cuMemAddressFree(addr, num_bytes));
267	    }
268	
269	    // Create a NUMA-local CPU segment and export its POSIX FD handle.
270	    // Returns (pid, fd) handle for cross-process sharing.
271	    static cpu_handle_t create_cpu_handle(const int64_t& num_cpu_bytes) {
272	        EP_HOST_ASSERT(num_cpu_bytes > 0 and num_cpu_bytes % kNumAlignmentBytes == 0);
273	
274	        DeviceContext ctx;
275	        auto cpu_prop = ctx.cpu_alloc_prop();
276	
277	        CUmemGenericAllocationHandle handle;
278	        cumem_create_with_fallback(&handle, num_cpu_bytes, &cpu_prop);
279	
280	        int fd = -1;
281	        CUDA_DRIVER_CHECK(lazy_cuMemExportToShareableHandle(
282	            &fd, handle, CU_MEM_HANDLE_TYPE_POSIX_FILE_DESCRIPTOR, 0));
283	
284	        // Release the allocation handle -- the POSIX FD keeps the physical memory alive
285	        CUDA_DRIVER_CHECK(lazy_cuMemRelease(handle));
286	
287	        return {getpid(), fd};
288	    }
289	};
290	
291	static std::shared_ptr<SymmetricMemory> alloc(const int64_t& num_gpu_bytes, const int64_t& num_cpu_bytes,
292	                                              const bool& allow_hybrid_mode = false,
293	                                              const int& num_scaleup_ranks = 0, const int& scaleout_rank_idx = 0,
294	                                              const cpu_comm_t& cpu_comm = {}) {
295	    EP_HOST_ASSERT(num_gpu_bytes > 0 and num_gpu_bytes % kNumAlignmentBytes == 0);
296	    EP_HOST_ASSERT(num_cpu_bytes >= 0 and num_cpu_bytes % kNumAlignmentBytes == 0);
297	
298	    std::shared_ptr<SymmetricMemory> result;
299	    if (num_cpu_bytes > 0) {
300	        if (allow_hybrid_mode) {
301	            result = std::make_shared<HybridElasticSymmetricMemory>(
302	                cpu_comm, num_gpu_bytes, num_cpu_bytes,
303	                num_scaleup_ranks, scaleout_rank_idx);
304	        } else {
305	            result = std::make_shared<ElasticSymmetricMemory>(
306	                num_gpu_bytes, num_cpu_bytes);
307	        }
308	    } else {
309	        result = std::make_shared<GPUSymmetricMemory>(num_gpu_bytes);
310	    }
311	
312	    // TODO: move all variables into NCCL runtime
313	    // Enable NCCL elastic buffer register if the allocator may produce CPU-backed segments
314	    if (dynamic_cast<ElasticSymmetricMemory*>(result.get()) != nullptr)
315	        setenv("NCCL_ELASTIC_BUFFER_REGISTER", "1", 0);
316	    return result;
317	}
318	
319	}  // namespace deep_ep::symmetric
